41	const groupBasePrice = (type: string, count: number): number => {
42	  const lineTotal = basePremium({ type }) * count;
43	  const blockApplies = COMPONENT_TYPES.has(type) && count === 3;
44	  return blockApplies ? BLOCK_BASE : lineTotal;
45	};
