53	const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
54	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
55	  {
56	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
57	    rate: HIGH_ENCHANTMENT_SURCHARGE,
58	  },
