77	  const policyModifier = baseTotal * policyModifierRate(customer, quoteIndex);
78	  const beforeFee = baseTotal + firstInsurance + itemSurcharges(items) + policyModifier;
79	  return roundUp(beforeFee + PROCESSING_FEE);
80	};
